const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const eventId = body.event?.id ?? body.eventId;
const jobId = job.id ?? body.jobId;
const callbackUrl = body.callbackUrl;
const callbackSecret = body.callbackSecret;
if (!jobId || !eventId || !callbackUrl) {
  return [];
}
const brief = job.brief ?? { title: job.seedKeyword ?? body.seedKeyword ?? 'Untitled draft', outline: [], angle: '', audience: '' };
const outline = brief.outline?.length ? brief.outline : ['Introduction', 'Core section', 'Practical section', 'FAQs'];
return [{ json: {
  eventId,
  jobId,
  callbackUrl,
  callbackSecret,
  draft: {
    intro: `This draft opens the article "${brief.title}" with a concise answer and a reader-first framing based on the selected SEO angle.`,
    sections: outline.slice(0, 4).map((heading, index) => ({
      heading,
      body: index === 0
        ? 'Start with the direct answer, search intent, and why this topic matters now.'
        : 'Expand the point with practical detail, local context, trusted references, and clear takeaways.'
    })),
    conclusion: 'Close with a concise summary, next steps, and internal-link opportunities for the cluster.'
  }
}}];
